use {async_trait::async_trait, secrecy::Secret, sqlx::SqlitePool};

use crate::{
    Error, Result,
    store::CrmStore,
    types::{
        Contact, ContactChannel, ContactStage, Interaction, InteractionKind, Matter, MatterPhase,
        MatterStatus, PracticeArea,
    },
};

// ── SQLite-backed CRM store ───────────────────────────────────────────────────

/// SQLite-backed implementation of [`CrmStore`].
pub struct SqliteCrmStore {
    pool: SqlitePool,
}

impl SqliteCrmStore {
    pub fn new(pool: SqlitePool) -> Self {
        Self { pool }
    }
}

// ── Row types ─────────────────────────────────────────────────────────────────

#[derive(sqlx::FromRow)]
struct ContactRow {
    id: String,
    name: String,
    source: Option<String>,
    external_id: Option<String>,
    email: Option<String>,
    phone: Option<String>,
    stage: String,
    metadata: Option<String>,
    created_at: i64,
    updated_at: i64,
}

impl TryFrom<ContactRow> for Contact {
    type Error = Error;

    fn try_from(r: ContactRow) -> Result<Self> {
        let stage = r
            .stage
            .parse::<ContactStage>()
            .map_err(|_| Error::parse("contact.stage", &r.stage))?;
        Ok(Contact {
            id: r.id,
            name: r.name,
            source: r.source,
            external_id: r.external_id,
            email: r.email.map(Secret::new),
            phone: r.phone.map(Secret::new),
            stage,
            metadata: serde_json::from_str(r.metadata.as_deref().unwrap_or("{}"))?,
            created_at: r.created_at as u64,
            updated_at: r.updated_at as u64,
        })
    }
}

#[derive(sqlx::FromRow)]
struct ContactChannelRow {
    id: String,
    contact_id: String,
    channel_type: String,
    channel_id: String,
    display_name: Option<String>,
    verified: i64,
    created_at: i64,
    updated_at: i64,
}

impl From<ContactChannelRow> for ContactChannel {
    fn from(r: ContactChannelRow) -> Self {
        Self {
            id: r.id,
            contact_id: r.contact_id,
            channel_type: r.channel_type,
            channel_id: r.channel_id,
            display_name: r.display_name,
            verified: r.verified != 0,
            created_at: r.created_at as u64,
            updated_at: r.updated_at as u64,
        }
    }
}

#[derive(sqlx::FromRow)]
struct MatterRow {
    id: String,
    contact_id: String,
    title: String,
    description: Option<String>,
    status: String,
    phase: String,
    practice_area: String,
    created_at: i64,
    updated_at: i64,
}

impl TryFrom<MatterRow> for Matter {
    type Error = Error;

    fn try_from(r: MatterRow) -> Result<Self> {
        let status = r
            .status
            .parse::<MatterStatus>()
            .map_err(|_| Error::parse("matter.status", &r.status))?;
        let phase = r
            .phase
            .parse::<MatterPhase>()
            .map_err(|_| Error::parse("matter.phase", &r.phase))?;
        let practice_area = r
            .practice_area
            .parse::<PracticeArea>()
            .map_err(|_| Error::parse("matter.practice_area", &r.practice_area))?;
        Ok(Matter {
            id: r.id,
            contact_id: r.contact_id,
            title: r.title,
            description: r.description,
            status,
            phase,
            practice_area,
            created_at: r.created_at as u64,
            updated_at: r.updated_at as u64,
        })
    }
}

#[derive(sqlx::FromRow)]
struct InteractionRow {
    id: String,
    contact_id: String,
    matter_id: Option<String>,
    kind: String,
    summary: String,
    channel: Option<String>,
    created_at: i64,
    updated_at: i64,
}

impl TryFrom<InteractionRow> for Interaction {
    type Error = Error;

    fn try_from(r: InteractionRow) -> Result<Self> {
        let kind = r
            .kind
            .parse::<InteractionKind>()
            .map_err(|_| Error::parse("interaction.kind", &r.kind))?;
        Ok(Interaction {
            id: r.id,
            contact_id: r.contact_id,
            matter_id: r.matter_id,
            kind,
            summary: r.summary,
            channel: r.channel,
            created_at: r.created_at as u64,
            updated_at: r.updated_at as u64,
        })
    }
}

// ── CrmStore implementation ───────────────────────────────────────────────────

#[async_trait]
impl CrmStore for SqliteCrmStore {
    // ── Contacts ──────────────────────────────────────────────────────────────

    async fn list(&self) -> Result<Vec<Contact>> {
        let rows = sqlx::query_as::<_, ContactRow>(
            "SELECT id, name, source, external_id, email, phone, stage, metadata, \
             created_at, updated_at FROM contacts ORDER BY updated_at DESC",
        )
        .fetch_all(&self.pool)
        .await?;

        rows.into_iter().map(Contact::try_from).collect()
    }

    async fn get(&self, id: &str) -> Result<Option<Contact>> {
        let row = sqlx::query_as::<_, ContactRow>(
            "SELECT id, name, source, external_id, email, phone, stage, metadata, \
             created_at, updated_at FROM contacts WHERE id = ?",
        )
        .bind(id)
        .fetch_optional(&self.pool)
        .await?;

        row.map(Contact::try_from).transpose()
    }

    async fn get_by_external(
        &self,
        source: &str,
        external_id: &str,
    ) -> Result<Option<Contact>> {
        let row = sqlx::query_as::<_, ContactRow>(
            "SELECT id, name, source, external_id, email, phone, stage, metadata, \
             created_at, updated_at FROM contacts WHERE source = ? AND external_id = ?",
        )
        .bind(source)
        .bind(external_id)
        .fetch_optional(&self.pool)
        .await?;

        row.map(Contact::try_from).transpose()
    }

    async fn upsert(&self, contact: Contact) -> Result<()> {
        use secrecy::ExposeSecret;
        let metadata = serde_json::to_string(&contact.metadata)?;
        sqlx::query(
            r#"INSERT INTO contacts
               (id, name, source, external_id, email, phone, stage, metadata, created_at, updated_at)
               VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
               ON CONFLICT(id) DO UPDATE SET
                 name        = excluded.name,
                 source      = excluded.source,
                 external_id = excluded.external_id,
                 email       = excluded.email,
                 phone       = excluded.phone,
                 stage       = excluded.stage,
                 metadata    = excluded.metadata,
                 updated_at  = excluded.updated_at"#,
        )
        .bind(&contact.id)
        .bind(&contact.name)
        .bind(&contact.source)
        .bind(&contact.external_id)
        .bind(contact.email.as_ref().map(|s| s.expose_secret().clone()))
        .bind(contact.phone.as_ref().map(|s| s.expose_secret().clone()))
        .bind(contact.stage.as_str())
        .bind(&metadata)
        .bind(contact.created_at as i64)
        .bind(contact.updated_at as i64)
        .execute(&self.pool)
        .await?;
        Ok(())
    }

    async fn delete(&self, id: &str) -> Result<()> {
        sqlx::query("DELETE FROM contacts WHERE id = ?")
            .bind(id)
            .execute(&self.pool)
            .await?;
        Ok(())
    }

    // ── Contact channels ──────────────────────────────────────────────────────

    async fn list_channels_for_contact(
        &self,
        contact_id: &str,
    ) -> Result<Vec<ContactChannel>> {
        let rows = sqlx::query_as::<_, ContactChannelRow>(
            "SELECT id, contact_id, channel_type, channel_id, display_name, verified, \
             created_at, updated_at FROM contact_channels \
             WHERE contact_id = ? ORDER BY updated_at DESC",
        )
        .bind(contact_id)
        .fetch_all(&self.pool)
        .await?;

        Ok(rows.into_iter().map(ContactChannel::from).collect())
    }

    async fn get_channel_by_external(
        &self,
        channel_type: &str,
        channel_id: &str,
    ) -> Result<Option<ContactChannel>> {
        let row = sqlx::query_as::<_, ContactChannelRow>(
            "SELECT id, contact_id, channel_type, channel_id, display_name, verified, \
             created_at, updated_at FROM contact_channels \
             WHERE channel_type = ? AND channel_id = ?",
        )
        .bind(channel_type)
        .bind(channel_id)
        .fetch_optional(&self.pool)
        .await?;

        Ok(row.map(ContactChannel::from))
    }

    async fn upsert_channel(&self, channel: ContactChannel) -> Result<()> {
        sqlx::query(
            r#"INSERT INTO contact_channels
               (id, contact_id, channel_type, channel_id, display_name, verified, created_at, updated_at)
               VALUES (?, ?, ?, ?, ?, ?, ?, ?)
               ON CONFLICT(id) DO UPDATE SET
                 contact_id   = excluded.contact_id,
                 channel_type = excluded.channel_type,
                 channel_id   = excluded.channel_id,
                 display_name = excluded.display_name,
                 verified     = excluded.verified,
                 updated_at   = excluded.updated_at"#,
        )
        .bind(&channel.id)
        .bind(&channel.contact_id)
        .bind(&channel.channel_type)
        .bind(&channel.channel_id)
        .bind(&channel.display_name)
        .bind(channel.verified as i64)
        .bind(channel.created_at as i64)
        .bind(channel.updated_at as i64)
        .execute(&self.pool)
        .await?;
        Ok(())
    }

    async fn delete_channel(&self, id: &str) -> Result<()> {
        sqlx::query("DELETE FROM contact_channels WHERE id = ?")
            .bind(id)
            .execute(&self.pool)
            .await?;
        Ok(())
    }

    // ── Matters ───────────────────────────────────────────────────────────────

    async fn list_matters(&self) -> Result<Vec<Matter>> {
        let rows = sqlx::query_as::<_, MatterRow>(
            "SELECT id, contact_id, title, description, status, phase, practice_area, \
             created_at, updated_at FROM matters ORDER BY updated_at DESC",
        )
        .fetch_all(&self.pool)
        .await?;

        rows.into_iter().map(Matter::try_from).collect()
    }

    async fn list_matters_by_contact(&self, contact_id: &str) -> Result<Vec<Matter>> {
        let rows = sqlx::query_as::<_, MatterRow>(
            "SELECT id, contact_id, title, description, status, phase, practice_area, \
             created_at, updated_at FROM matters \
             WHERE contact_id = ? ORDER BY updated_at DESC",
        )
        .bind(contact_id)
        .fetch_all(&self.pool)
        .await?;

        rows.into_iter().map(Matter::try_from).collect()
    }

    async fn get_matter(&self, id: &str) -> Result<Option<Matter>> {
        let row = sqlx::query_as::<_, MatterRow>(
            "SELECT id, contact_id, title, description, status, phase, practice_area, \
             created_at, updated_at FROM matters WHERE id = ?",
        )
        .bind(id)
        .fetch_optional(&self.pool)
        .await?;

        row.map(Matter::try_from).transpose()
    }

    async fn upsert_matter(&self, matter: Matter) -> Result<()> {
        sqlx::query(
            r#"INSERT INTO matters
               (id, contact_id, title, description, status, phase, practice_area, created_at, updated_at)
               VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)
               ON CONFLICT(id) DO UPDATE SET
                 contact_id    = excluded.contact_id,
                 title         = excluded.title,
                 description   = excluded.description,
                 status        = excluded.status,
                 phase         = excluded.phase,
                 practice_area = excluded.practice_area,
                 updated_at    = excluded.updated_at"#,
        )
        .bind(&matter.id)
        .bind(&matter.contact_id)
        .bind(&matter.title)
        .bind(&matter.description)
        .bind(matter.status.as_str())
        .bind(matter.phase.as_str())
        .bind(matter.practice_area.as_str())
        .bind(matter.created_at as i64)
        .bind(matter.updated_at as i64)
        .execute(&self.pool)
        .await?;
        Ok(())
    }

    async fn delete_matter(&self, id: &str) -> Result<()> {
        sqlx::query("DELETE FROM matters WHERE id = ?")
            .bind(id)
            .execute(&self.pool)
            .await?;
        Ok(())
    }

    // ── Interactions ──────────────────────────────────────────────────────────

    async fn list_interactions_by_contact(
        &self,
        contact_id: &str,
    ) -> Result<Vec<Interaction>> {
        let rows = sqlx::query_as::<_, InteractionRow>(
            "SELECT id, contact_id, matter_id, kind, summary, channel, \
             created_at, updated_at FROM interactions \
             WHERE contact_id = ? ORDER BY updated_at DESC",
        )
        .bind(contact_id)
        .fetch_all(&self.pool)
        .await?;

        rows.into_iter().map(Interaction::try_from).collect()
    }

    async fn list_interactions_by_matter(
        &self,
        matter_id: &str,
    ) -> Result<Vec<Interaction>> {
        let rows = sqlx::query_as::<_, InteractionRow>(
            "SELECT id, contact_id, matter_id, kind, summary, channel, \
             created_at, updated_at FROM interactions \
             WHERE matter_id = ? ORDER BY updated_at DESC",
        )
        .bind(matter_id)
        .fetch_all(&self.pool)
        .await?;

        rows.into_iter().map(Interaction::try_from).collect()
    }

    async fn get_interaction(&self, id: &str) -> Result<Option<Interaction>> {
        let row = sqlx::query_as::<_, InteractionRow>(
            "SELECT id, contact_id, matter_id, kind, summary, channel, \
             created_at, updated_at FROM interactions WHERE id = ?",
        )
        .bind(id)
        .fetch_optional(&self.pool)
        .await?;

        row.map(Interaction::try_from).transpose()
    }

    async fn upsert_interaction(&self, interaction: Interaction) -> Result<()> {
        sqlx::query(
            r#"INSERT INTO interactions
               (id, contact_id, matter_id, kind, summary, channel, created_at, updated_at)
               VALUES (?, ?, ?, ?, ?, ?, ?, ?)
               ON CONFLICT(id) DO UPDATE SET
                 contact_id = excluded.contact_id,
                 matter_id  = excluded.matter_id,
                 kind       = excluded.kind,
                 summary    = excluded.summary,
                 channel    = excluded.channel,
                 updated_at = excluded.updated_at"#,
        )
        .bind(&interaction.id)
        .bind(&interaction.contact_id)
        .bind(&interaction.matter_id)
        .bind(interaction.kind.as_str())
        .bind(&interaction.summary)
        .bind(&interaction.channel)
        .bind(interaction.created_at as i64)
        .bind(interaction.updated_at as i64)
        .execute(&self.pool)
        .await?;
        Ok(())
    }

