#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, Serialize, Deserialize)]
#[serde(rename_all = "snake_case")]
pub enum InteractionKind {
    /// Phone or video call.
    Call,
    /// Email exchange.
    Email,
    /// Chat message (any channel).
    Message,
    /// In-person or virtual meeting.
    Meeting,
